113→		user_id: string;
114→		organization_id: string;
115→	}>
116→> {
117→	const start = Date.now();
118→	while (Date.now() - start < timeoutMs) {
119→		try {
120→			const results = await executor.query<{
121→				session_id: string;
122→				project_path: string;
123→				repository: string;
124→				tag: string;
125→				user_id: string;
126→				organization_id: string;
127→			}>(
128→				`SELECT session_id, project_path, repository, tag, user_id, organization_id FROM rudel.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
129→			);
130→			if (results.length > 0) return results;
131→		} catch {
132→			// Transient ClickHouse errors (e.g. S3 storage) - retry
133→		}
134→		await new Promise((r) => setTimeout(r, intervalMs));
135→	}
136→	return [];
